class Dog(val name: String, val breed: String)
val d = Dog("Rex", "Labrador")
println(d.name)

class Circle(val radius: Double) {
    init {
        println("Circle with radius $radius created")
    }
}
val c = Circle(5.0)

class Counter {
    var count = 0
    fun increment() { count++ }
    fun value() = count
}
val c = Counter()
c.increment()
c.increment()
println(c.value())

class Box(val size: Int) {
    fun describe(): String {
        return "Box of size ${this.size}"
    }
}
println(Box(10).describe())

class Message(val text: String) {
    constructor(code: Int) : this("Code: $code")
}
println(Message(42).text)
